const OptaTab: React.FC = () => {
    const [selectedLeague, setSelectedLeague] = useState(COMPETITIONS[3]); // Default EPL
    const [analysis, setAnalysis] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [sources, setSources] = useState<any[]>([]);

    const generateAnalysis = async () => {
        setLoading(true);
        setAnalysis("");
        setSources([]);

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Provide a high-level tactical intelligence briefing for the ${selectedLeague.name}. 
                Identify the current top 3 title contenders, 1 "statistical outlier" team or player performing unexpectedly well, and a prediction for the next major matchday. 
                Keep it professional, concise, and formatted as a tactical report.`,
                config: {
                    tools: [{ googleSearch: {} }],
                },
            });

            setAnalysis(response.text || "Analysis engine failed to respond.");
            if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
                setSources(response.candidates[0].groundingMetadata.groundingChunks);
            }
        } catch (error) {
            setAnalysis("CRITICAL ERROR: Intelligence feed interrupted. Please check API credentials.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="pb-32 pt-24 min-h-screen bg-black text-white relative overflow-hidden animate-fade-in">
            <div className="absolute inset-0 bg-[linear-gradient(rgba(var(--primary-rgb),0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(var(--primary-rgb),0.02)_1px,transparent_1px)] bg-[size:40px_40px] z-0"></div>

            <div className="px-8 mb-10 relative z-10">
                <div className="flex items-center gap-4 mb-4">
                    <div className="w-2 h-2 rounded-full bg-[var(--primary-color)] shadow-[0_0_8px_var(--primary-color)]"></div>
                    <span className="text-xs font-mono text-[var(--primary-color)] uppercase tracking-widest font-bold">Data Intelligence Engine</span>
                </div>
                <h2 className="text-6xl font-display font-black text-white uppercase tracking-tighter leading-none">
                    OPTA <span className="text-transparent bg-clip-text bg-gradient-to-r from-[var(--primary-color)] to-white">VISION</span>
                </h2>
            </div>

            <div className="px-6 space-y-6 relative z-10">
                {/* AI Terminal */}
                <div className="bg-[#0a0a0a] border border-white/5 rounded-[3rem] p-10 shadow-3xl relative overflow-hidden group/terminal">
                    <div className="absolute top-0 right-0 p-8 opacity-5 text-9xl text-[var(--primary-color)] font-display font-black uppercase pointer-events-none">TACTICAL</div>

                    <div className="relative z-10">
                        <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 mb-10">
                            <div>
                                <h3 className="text-3xl font-display font-bold uppercase tracking-tight mb-2">Live Analysis Core</h3>
                                <p className="text-slate-500 font-light max-w-md">Gemini-Powered strategic forecasting with real-time Google grounding.</p>
                            </div>
                            <div className="flex gap-4">
                                <select 
                                    className="bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-sm focus:border-[var(--primary-color)] outline-none appearance-none cursor-pointer pr-10 relative"
                                    value={selectedLeague.id}
                                    onChange={(e) => setSelectedLeague(COMPETITIONS.find(c => c.id === e.target.value) || COMPETITIONS[0])}
                                >
                                    {COMPETITIONS.map(c => <option key={c.id} value={c.id}>{c.shortName}</option>)}
                                </select>
                                <button 
                                    onClick={generateAnalysis}
                                    disabled={loading}
                                    className="bg-[var(--primary-color)] text-black font-black px-8 py-3 rounded-xl uppercase text-xs tracking-widest hover:brightness-110 disabled:opacity-50 transition-all flex items-center gap-3"
                                >
                                    {loading ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-bolt"></i>}
                                    {loading ? "Analysing..." : "Generate Brief"}
                                </button>
                            </div>
                        </div>

                        <div className="min-h-[300px] bg-black/40 border border-white/5 rounded-2xl p-8 font-mono text-sm leading-relaxed relative overflow-hidden">
                            {loading && (
                                <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm z-20">
                                    <div className="w-12 h-12 border-2 border-[var(--primary-color)] border-t-transparent rounded-full animate-spin mb-4"></div>
                                    <span className="text-[10px] uppercase tracking-[0.5em] text-[var(--primary-color)] animate-pulse">Scanning Global Datasets...</span>
                                </div>
                            )}

                            {!analysis && !loading && (
                                <div className="flex flex-col items-center justify-center h-full text-slate-700 py-20 text-center">
                                    <i className="fa-solid fa-robot text-5xl mb-6 opacity-20"></i>
                                    <p className="uppercase tracking-[0.2em] font-black">System Ready for Input</p>
                                    <p className="text-[10px] mt-2 opacity-50">Select a competition and initiate tactical scan</p>
                                </div>
                            )}

                            {analysis && (
                                <div className="space-y-6 animate-fade-in text-slate-300">
                                    <div className="flex items-center gap-2 text-[var(--primary-color)] font-black text-[10px] uppercase tracking-widest mb-4">
                                        <i className="fa-solid fa-check-circle"></i> Insight Generated
                                    </div>
                                    <div className="whitespace-pre-wrap leading-relaxed border-l-2 border-[var(--primary-color)]/30 pl-6 italic">
                                        {analysis}
                                    </div>

                                    {sources.length > 0 && (
                                        <div className="mt-10 pt-8 border-t border-white/5">
                                            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center gap-2">
                                                <i className="fa-solid fa-link"></i> Verification Sources
                                            </p>
                                            <div className="flex flex-wrap gap-3">
