                                                    >
                                                        {chunk.web.title || "Reference Source"}
                                                    </a>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Legacy Links */}
                <div className="grid grid-cols-2 gap-6">
                    <div 
                        onClick={() => window.open(OPTA_ANALYST_LINK, "_blank")}
                        className="bg-slate-900/30 border border-white/5 rounded-[2rem] p-8 hover:bg-slate-800/50 transition-all cursor-pointer group"
                    >
                        <i className="fa-solid fa-fire text-orange-500 text-3xl mb-6 group-hover:scale-110 transition-transform"></i>
                        <h4 className="font-display font-bold text-2xl uppercase mb-1">Heatmaps</h4>
                        <p className="text-sm text-slate-500 font-light">Live tracking</p>
                    </div>

                    <div className="bg-slate-900/30 border border-white/5 rounded-[2rem] p-8 hover:bg-slate-800/50 transition-all cursor-pointer group" onClick={() => window.open("https://theanalyst.com/stats", "_blank")}>
                        <i className="fa-solid fa-bullseye text-cyan-400 text-3xl mb-6 group-hover:scale-110 transition-transform"></i>
                        <h4 className="font-display font-bold text-2xl uppercase mb-1">xG Matrix</h4>
                        <p className="text-sm text-slate-500 font-light">Goal quality</p>
                    </div>
